esqlQuery.esql:
FROM logs-*
// Restrict to Azure Activity Logs (Policy category)
| WHERE azure.category IS NOT NULL
| WHERE azure.category == "Policy"
// compliance_check: false indicates real-time policy effect (non-compliance), true is evaluation only
| WHERE azure.policy.compliance_check == false
// Aggregate by resource and policy for context
| STATS violation_count = COUNT(*) BY cloud.resource_id, azure.operation.name
// Minimum violations to alert — tune to reduce noise
| WHERE violation_count >= 2
| SORT violation_count DESC
| LIMIT 20
